cop-003.implementationNotes:
# Step 1: Connect and create CA policy targeting Office365
Connect-MgGraph -Scopes "Policy.ReadWrite.ConditionalAccess"

# Step 2: Require MFA + compliant device for Copilot users group
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
  DisplayName = "Require MFA + Compliant Device for Copilot"
  State = "enabledForReportingButNotEnforced"
  Conditions = @{
    Applications = @{ IncludeApplications = @("Office365") }
    Users = @{ IncludeGroups = @("<Copilot-Users-Group-ID>") }
  }
  GrantControls = @{ Operator = "AND"; BuiltInControls = @("mfa","compliantDevice") }
}

# Step 3: Block legacy auth protocols for Copilot users
# Step 4: Review sign-in logs for 1 week in report-only mode
# Step 5: Enable enforcement after validating no user impact
# Step 6: Exclude break-glass accounts with separate monitoring

cop-005.advancedDetection:
// KQL: Detect jailbreak attempts and sensitive data access via Copilot
let JailbreakAttempts = AuditLogs
| where TimeGenerated > ago(24h)
| where OperationName == "CopilotInteraction"
| extend AuditDetail = parse_json(AdditionalDetails)
| where AuditDetail.JailbreakDetected == true
| project TimeGenerated, UserPrincipalName, AuditDetail;
// Alert on any jailbreak detection
JailbreakAttempts
| extend AlertSeverity = "High"
